import {
  CheckCircleFilled,
  LockOutlined,
  MailOutlined,
  UserOutlined,
} from "@ant-design/icons";
import { Button, Form, Input, Modal, Typography, message } from "antd";
import { useState } from "react";
import { signup } from "../utils";

const { Paragraph, Text, Title } = Typography;

const SignupForm = ({ buttonClassName, buttonLabel = "Register" }) => {
  const [displayModal, setDisplayModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [accountCreated, setAccountCreated] = useState(false);
  const [form] = Form.useForm();

  const openModal = () => {
    setAccountCreated(false);
    setDisplayModal(true);
  };

  const handleCancel = () => {
    setDisplayModal(false);
    setAccountCreated(false);
    form.resetFields();
  };

  const onFinish = (data) => {
    setLoading(true);

    signup(data)
      .then(() => {
        form.resetFields();
        setAccountCreated(true);
        message.success("Account Created");
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setLoading(false);
      });
  };

  return (
    <>
      <Button
        className={buttonClassName}
        shape="round"
        type="primary"
        onClick={openModal}
      >
        {buttonLabel}
      </Button>
      <Modal
        className="fashion-modal"
        title={null}
        open={displayModal}
        onCancel={handleCancel}
        footer={null}
        destroyOnClose
      >
        {accountCreated ? (
          <div className="signup-success">
            <CheckCircleFilled className="signup-success__icon" />
            <Text className="signup-success__eyebrow">Registration complete</Text>
            <Title level={3} className="signup-success__title">
              Account Created
            </Title>
            <Paragraph className="signup-success__text">
              Your customer profile is ready. Close this panel and sign in to start
              adding items, paying, and placing orders.
            </Paragraph>
            <Button className="auth-submit signup-success__button" type="primary" block onClick={handleCancel}>
              Continue to sign in
            </Button>
          </div>
        ) : (
          <>
            <div className="signup-modal__hero">
              <Text className="signup-modal__eyebrow">Create account</Text>
              <Title level={3} className="signup-modal__title">
                Join the polished version of the ordering flow.
              </Title>
              <Paragraph className="signup-modal__text">
                Register a customer profile so the storefront can save your identity
                for cart, payment, and order actions.
              </Paragraph>
            </div>

            <Form form={form} name="register" onFinish={onFinish} layout="vertical" preserve={false}>
              <Form.Item
                label="Email"
                name="email"
                rules={[{ required: true, message: "Please input your email" }]}
              >
                <Input className="auth-input" prefix={<MailOutlined />} placeholder="you@example.com" />
              </Form.Item>

              <Form.Item
                label="Password"
                name="password"
                rules={[{ required: true, message: "Please input your password" }]}
              >
                <Input.Password
                  className="auth-input"
                  prefix={<LockOutlined />}
                  placeholder="Password"
                />
              </Form.Item>

              <Form.Item
                label="First name"
                name="first_name"
                rules={[{ required: true, message: "Please input your first name" }]}
              >
                <Input className="auth-input" prefix={<UserOutlined />} placeholder="First name" />
              </Form.Item>

              <Form.Item
                label="Last name"
                name="last_name"
                rules={[{ required: true, message: "Please input your last name" }]}
              >
                <Input className="auth-input" prefix={<UserOutlined />} placeholder="Last name" />
              </Form.Item>

              <Form.Item style={{ marginBottom: 0 }}>
                <Button className="auth-submit" type="primary" htmlType="submit" loading={loading} block>
                  Create account
                </Button>
              </Form.Item>
            </Form>
          </>
        )}
      </Modal>
    </>
  );
};

export default SignupForm;
